836:     private CompletableFuture<Void> triggerTasks(
837:             CheckpointTriggerRequest request, long timestamp, PendingCheckpoint checkpoint) {
838:         // no exception, no discarding, everything is OK
839:         final long checkpointId = checkpoint.getCheckpointID();
840: 
841:         final SnapshotType type;
842:         if (this.forceFullSnapshot && !request.props.isSavepoint()) {
843:             type = FULL_CHECKPOINT;
844:         } else {
845:             type = request.props.getCheckpointType();
846:         }
847: 
848:         final CheckpointOptions checkpointOptions =
849:                 CheckpointOptions.forConfig(
850:                         type,
851:                         checkpoint.getCheckpointStorageLocation().getLocationReference(),
852:                         isExactlyOnceMode,
853:                         unalignedCheckpointsEnabled,
854:                         alignedCheckpointTimeout);
855: 
856:         // send messages to the tasks to trigger their checkpoints
857:         List<CompletableFuture<Acknowledge>> acks = new ArrayList<>();
858:         for (Execution execution : checkpoint.getCheckpointPlan().getTasksToTrigger()) {
859:             if (request.props.isSynchronous()) {
860:                 acks.add(
861:                         execution.triggerSynchronousSavepoint(
862:                                 checkpointId, timestamp, checkpointOptions));
863:             } else {
864:                 acks.add(execution.triggerCheckpoint(checkpointId, timestamp, checkpointOptions));
865:             }
866:         }
867:         return FutureUtils.waitForAll(acks);
868:     }
