377:     /**
378:      * Acknowledges the task with the given execution attempt id and the given subtask state.
379:      *
380:      * @param executionAttemptId of the acknowledged task
381:      * @param operatorSubtaskStates of the acknowledged task
382:      * @param metrics Checkpoint metrics for the stats
383:      * @return TaskAcknowledgeResult of the operation
384:      */
385:     public TaskAcknowledgeResult acknowledgeTask(
386:             ExecutionAttemptID executionAttemptId,
387:             TaskStateSnapshot operatorSubtaskStates,
388:             CheckpointMetrics metrics) {
389: 
390:         synchronized (lock) {
391:             if (disposed) {
392:                 return TaskAcknowledgeResult.DISCARDED;
393:             }
394: 
395:             final ExecutionVertex vertex = notYetAcknowledgedTasks.remove(executionAttemptId);
396: 
397:             if (vertex == null) {
398:                 if (acknowledgedTasks.contains(executionAttemptId)) {
399:                     return TaskAcknowledgeResult.DUPLICATE;
400:                 } else {
401:                     return TaskAcknowledgeResult.UNKNOWN;
402:                 }
403:             } else {
404:                 acknowledgedTasks.add(executionAttemptId);
405:             }
406: 
407:             long ackTimestamp = System.currentTimeMillis();
408:             if (operatorSubtaskStates != null && operatorSubtaskStates.isTaskDeployedAsFinished()) {
409:                 checkpointPlan.reportTaskFinishedOnRestore(vertex);
410:             } else {
411:                 for (OperatorIDPair operatorIDPair : vertex.getJobVertex().getOperatorIDs()) {
412:                     updateOperatorState(vertex, operatorSubtaskStates, operatorIDPair);
413:                 }
414: 
415:                 if (operatorSubtaskStates != null && operatorSubtaskStates.isTaskFinished()) {
416:                     checkpointPlan.reportTaskHasFinishedOperators(vertex);
417:                 }
418:             }
419: 
420:             ++numAcknowledgedTasks;
421: 
422:             // publish the checkpoint statistics
423:             // to prevent null-pointers from concurrent modification, copy reference onto stack
424:             if (pendingCheckpointStats != null) {
425:                 // Do this in millis because the web frontend works with them
426:                 long alignmentDurationMillis = metrics.getAlignmentDurationNanos() / 1_000_000;
427:                 long checkpointStartDelayMillis =
428:                         metrics.getCheckpointStartDelayNanos() / 1_000_000;
429: 
430:                 SubtaskStateStats subtaskStateStats =
431:                         new SubtaskStateStats(
432:                                 vertex.getParallelSubtaskIndex(),
433:                                 ackTimestamp,
434:                                 metrics.getBytesPersistedOfThisCheckpoint(),
435:                                 metrics.getTotalBytesPersisted(),
436:                                 metrics.getSyncDurationMillis(),
437:                                 metrics.getAsyncDurationMillis(),
438:                                 metrics.getBytesProcessedDuringAlignment(),
439:                                 metrics.getBytesPersistedDuringAlignment(),
440:                                 alignmentDurationMillis,
441:                                 checkpointStartDelayMillis,
442:                                 metrics.getUnalignedCheckpoint(),
443:                                 true);
444: 
445:                 LOG.trace(
446:                         "Checkpoint {} stats for {}: size={}Kb, duration={}ms, sync part={}ms, async part={}ms",
447:                         checkpointId,
448:                         vertex.getTaskNameWithSubtaskIndex(),
449:                         subtaskStateStats.getStateSize() == 0
450:                                 ? 0
451:                                 : subtaskStateStats.getStateSize() / 1024,
452:                         subtaskStateStats.getEndToEndDuration(
453:                                 pendingCheckpointStats.getTriggerTimestamp()),
454:                         subtaskStateStats.getSyncCheckpointDuration(),
455:                         subtaskStateStats.getAsyncCheckpointDuration());
456:                 pendingCheckpointStats.reportSubtaskStats(
457:                         vertex.getJobvertexId(), subtaskStateStats);
458:             }
459: 
460:             return TaskAcknowledgeResult.SUCCESS;
461:         }
462:     }
