464:     private void updateOperatorState(
465:             ExecutionVertex vertex,
466:             TaskStateSnapshot operatorSubtaskStates,
467:             OperatorIDPair operatorIDPair) {
468:         OperatorState operatorState = operatorStates.get(operatorIDPair.getGeneratedOperatorID());
469: 
470:         if (operatorState == null) {
471:             operatorState =
472:                     new OperatorState(
473:                             operatorIDPair.getUserDefinedOperatorName(),
474:                             operatorIDPair.getUserDefinedOperatorUid(),
475:                             operatorIDPair.getGeneratedOperatorID(),
476:                             vertex.getTotalNumberOfParallelSubtasks(),
477:                             vertex.getMaxParallelism());
478:             operatorStates.put(operatorIDPair.getGeneratedOperatorID(), operatorState);
479:         } else {
480:             operatorState.setOperatorName(operatorIDPair.getUserDefinedOperatorName());
481:             operatorState.setOperatorUid(operatorIDPair.getUserDefinedOperatorUid());
482:         }
483:         OperatorSubtaskState operatorSubtaskState =
484:                 operatorSubtaskStates == null
485:                         ? null
486:                         : operatorSubtaskStates.getSubtaskStateByOperatorID(
487:                                 operatorIDPair.getGeneratedOperatorID());
488: 
489:         if (operatorSubtaskState != null) {
490:             operatorState.putState(vertex.getParallelSubtaskIndex(), operatorSubtaskState);
491:         }
492:     }
