1211:             AcknowledgeCheckpoint message, String taskManagerLocationInfo)
1212:             throws CheckpointException {
1213:         if (shutdown || message == null) {
1214:             return false;
1215:         }
1216: 
1217:         if (!job.equals(message.getJob())) {
1218:             LOG.error(
1219:                     "Received wrong AcknowledgeCheckpoint message for job {} from {} : {}",
1220:                     job,
1221:                     taskManagerLocationInfo,
1222:                     message);
1223:             return false;
1224:         }
1225: 
1226:         final long checkpointId = message.getCheckpointId();
1227: 
1228:         synchronized (lock) {
1229:             // we need to check inside the lock for being shutdown as well, otherwise we
1230:             // get races and invalid error log messages
1231:             if (shutdown) {
1232:                 return false;
